const body = $input.first().json.body || $input.first().json;

// Supports both JSON body and URL-encoded form data
const firstName = body.firstName || body.first_name || body.name?.split(' ')[0] || '';
const lastName = body.lastName || body.last_name || body.name?.split(' ').slice(1).join(' ') || '';
const email = body.email || body.emailAddress || '';
const phone = body.phone || body.phoneNumber || body.whatsapp || '';
const service = body.service || body.serviceInterest || body.inquiry_type || 'General Enquiry';
const message = body.message || body.notes || body.comment || '';
const preferredTime = body.preferredTime || body.preferred_date || '';
const source = body.source || body.utm_source || 'Website Form';

return [{ json: {
  firstName,
  lastName,
  fullName: [firstName, lastName].filter(Boolean).join(' ') || 'Guest',
  email,
  phone,
  service,
  message,
  preferredTime,
  source,
  submittedAt: new Date().toISOString()
} }];

const now = new Date();
const hkOffset = 8 * 60;
const utcMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const hkMinutes = (utcMinutes + hkOffset) % (24 * 60);
const hkDay = new Date(now.getTime() + hkOffset * 60000).getUTCDay();

const isWeekday = hkDay >= 1 && hkDay <= 6;
const isOpenHours = hkMinutes >= 540 && hkMinutes < 1140;
const isBusinessHours = isWeekday && isOpenHours;

return [{ json: { ...$input.first().json, isBusinessHours } }];

const emailBody = $input.first().json.choices[0].message.content;
const formData = $('Extract Form Fields').first().json;
return [{ json: {
  ...formData,
  emailBody,
  emailSubject: `Thank you for your enquiry — ${formData.service}`
} }];
